/**
 * Authentication Middleware
 * Checks for a valid session before allowing access to protected routes.
 * Returns 401 Unauthorized if no valid session is found.
 */

module.exports = (req, res, next) => {
  // Check if session exists and has a user attached
  if (req.session && req.session.user) {
    return next();
  } else {
    return res.status(401).json({ message: 'Unauthorized' });
  }
};

/**
 * Authentication Routes
 * Defines endpoints for login and logout operations.
 *
 * POST /auth/login  - Authenticate user with username and password
 * POST /auth/logout - Destroy the current session
 */

const express = require('express');
const bcrypt = require('bcrypt');
const router = express.Router();

/**
 * Mock user data for demo purposes.
 * In production, users would be fetched from a database.
 * Password hash below corresponds to 'demo123' with salt rounds = 10.
 * To regenerate: bcrypt.hashSync('demo123', 10)
 */
const users = [
  {
    id: 1,
    username: 'demo',
    // Pre-hashed password for 'demo123'
    password: '$2b$10$N9qo8uLOickgx2ZMRZoMyeIjZAgcfl7p92ldGxad68LJZdL17lhWy',
  },
];

/**
 * POST /auth/login
 * Authenticates a user by comparing the provided password with the stored hash.
 *
 * Request body:
 *   { username: string, password: string }
 *
 * Response:
 *   200: { message: 'Login successful', user: { id, username } }
 *   400: { message: 'Username and password are required' }
 *   401: { message: 'Invalid credentials' }
 *   500: { message: 'Internal server error' }
 */
router.post('/login', async (req, res) => {
  try {
    const { username, password } = req.body;

    // Validate that both fields are provided
    if (!username || !password) {
      return res.status(400).json({ message: 'Username and password are required' });
    }

    // Find the user by username (case-insensitive)
    const user = users.find(u => u.username.toLowerCase() === username.toLowerCase());

    if (!user) {
      // Return generic message to avoid username enumeration
      return res.status(401).json({ message: 'Invalid credentials' });
    }

    // Compare provided password with stored hash
    const passwordMatch = await bcrypt.compare(password, user.password);

    if (!passwordMatch) {
      return res.status(401).json({ message: 'Invalid credentials' });
    }

    // Store safe user data in session (exclude password hash)
    req.session.user = {
      id: user.id,
      username: user.username,
    };

    return res.json({
      message: 'Login successful',
      user: { id: user.id, username: user.username },
    });
  } catch (err) {
    console.error('Login error:', err);
    return res.status(500).json({ message: 'Internal server error' });
  }
});

/**
 * POST /auth/logout
 * Destroys the current session, effectively logging the user out.
 *
 * Response:
 *   200: { message: 'Logout successful' }
 *   500: { message: 'Logout failed' }
 */
router.post('/logout', (req, res) => {
  req.session.destroy(err => {
    if (err) {
      console.error('Session destruction error:', err);
      return res.status(500).json({ message: 'Logout failed' });
    }
    // Clear the session cookie from the client
    res.clearCookie('connect.sid');
    return res.json({ message: 'Logout successful' });
  });
});

/**
 * GET /auth/me
 * Returns the currently authenticated user's info.
 * Useful for the UI to check session state on page load.
 *
 * Response:
 *   200: { user: { id, username } }
 *   401: { message: 'Not authenticated' }
 */
router.get('/me', (req, res) => {
  if (req.session && req.session.user) {
    return res.json({ user: req.session.user });
  }
  return res.status(401).json({ message: 'Not authenticated' });
});

module.exports = router;

/**
 * Express Application Entry Point
 * Sets up middleware, routes, and starts the HTTP server.
 */

const express = require('express');
const session = require('express-session');
const authRoutes = require('./routes/authRoutes');
const authMiddleware = require('./middleware/authMiddleware');

// Load environment variables from .env file
require('dotenv').config();

const app = express();

// ─── Middleware ───────────────────────────────────────────────────────────────

// Parse incoming JSON request bodies
app.use(express.json());

// Parse URL-encoded form data
app.use(express.urlencoded({ extended: true }));

// Session management
// SESSION_SECRET must be set in .env for production use
app.use(
  session({
    secret: process.env.SESSION_SECRET || 'fallback-dev-secret-change-in-production',
    resave: false,
    saveUninitialized: false, // Only save sessions that have been modified
    cookie: {
      httpOnly: true,          // Prevent client-side JS from reading the cookie
      secure: process.env.NODE_ENV === 'production', // HTTPS only in production
      maxAge: 1000 * 60 * 60 * 24, // 24 hours
    },
  })
);

// ─── Routes ───────────────────────────────────────────────────────────────────

// Authentication routes (login, logout, session check)
app.use('/auth', authRoutes);

// Example protected route — requires a valid session
app.get('/protected', authMiddleware, (req, res) => {
  res.json({
    message: 'This is a protected route',
    user: req.session.user,
  });
});

// Health check endpoint — publicly accessible
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// ─── 404 Handler ─────────────────────────────────────────────────────────────

app.use((req, res) => {
  res.status(404).json({ message: `Route ${req.method} ${req.path} not found` });
});

// ─── Global Error Handler ─────────────────────────────────────────────────────

// Must have 4 parameters for Express to treat it as an error handler
// eslint-disable-next-line no-unused-vars
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);
  res.status(500).json({
    message: 'An unexpected error occurred',
    ...(process.env.NODE_ENV !== 'production' && { error: err.message }),
  });
});

// ─── Server Start ─────────────────────────────────────────────────────────────

const PORT = process.env.PORT || 3000;

// Only start listening if this file is run directly (not imported in tests)
if (require.main === module) {
  app.listen(PORT, () => {
    console.log(`Server running on port ${PORT}`);
    console.log(`Environment: ${process.env.NODE_ENV || 'development'}`);
  });
}

// Export app for use in tests
module.exports = app;

