    "bcrypt": "^5.1.1",
    "dotenv": "^16.4.5",
    "express": "^4.19.2",
    "express-session": "^1.18.0"
  },
  "devDependencies": {
    "jest": "^29.7.0",
    "nodemon": "^3.1.0",
    "supertest": "^7.0.0"
  },
  "jest": {
    "testEnvironment": "node",
    "testMatch": [
      "**/tests/**/*.test.js"
    ]
  }
}

/**
 * Authentication Routes Integration Tests
 * Tests login, logout, and session management endpoints.
 */

const request = require('supertest');
const app = require('../../server/app');

describe('Authentication Routes', () => {
  // ─── POST /auth/login ───────────────────────────────────────────────────────

  describe('POST /auth/login', () => {
    it('should return 400 if username or password is missing', async () => {
      const res = await request(app).post('/auth/login').send({ username: 'demo' });
      expect(res.status).toBe(400);
      expect(res.body.message).toBe('Username and password are required');
    });

    it('should return 401 for invalid credentials', async () => {
      const res = await request(app)
        .post('/auth/login')
        .send({ username: 'demo', password: 'wrongpassword' });
      expect(res.status).toBe(401);
      expect(res.body.message).toBe('Invalid credentials');
    });

    it('should return 401 for non-existent user', async () => {
      const res = await request(app)
        .post('/auth/login')
        .send({ username: 'nonexistent', password: 'demo123' });
      expect(res.status).toBe(401);
      expect(res.body.message).toBe('Invalid credentials');
    });

    it('should return 200 and login message for valid credentials', async () => {
      const res = await request(app)
        .post('/auth/login')
        .send({ username: 'demo', password: 'demo123' });
      expect(res.status).toBe(200);
      expect(res.body.message).toBe('Login successful');
      expect(res.body.user).toHaveProperty('username', 'demo');
      // Password hash should never be returned
      expect(res.body.user).not.toHaveProperty('password');
    });
  });

  // ─── POST /auth/logout ──────────────────────────────────────────────────────

  describe('POST /auth/logout', () => {
    it('should return 200 and destroy session on logout', async () => {
      // First, log in to create a session
      const agent = request.agent(app);
      await agent.post('/auth/login').send({ username: 'demo', password: 'demo123' });

      // Then log out
      const res = await agent.post('/auth/logout');
      expect(res.status).toBe(200);
      expect(res.body.message).toBe('Logout successful');
    });

    it('should make protected routes inaccessible after logout', async () => {
      const agent = request.agent(app);

      // Log in
      await agent.post('/auth/login').send({ username: 'demo', password: 'demo123' });

      // Verify protected route is accessible
      const protectedBefore = await agent.get('/protected');
      expect(protectedBefore.status).toBe(200);

      // Log out
      await agent.post('/auth/logout');

      // Verify protected route is now inaccessible
      const protectedAfter = await agent.get('/protected');
      expect(protectedAfter.status).toBe(401);
    });
  });

  // ─── GET /auth/me ───────────────────────────────────────────────────────────

  describe('GET /auth/me', () => {
    it('should return 401 when not authenticated', async () => {
      const res = await request(app).get('/auth/me');
      expect(res.status).toBe(401);
    });

    it('should return current user when authenticated', async () => {
      const agent = request.agent(app);
      await agent.post('/auth/login').send({ username: 'demo', password: 'demo123' });

      const res = await agent.get('/auth/me');
      expect(res.status).toBe(200);
      expect(res.body.user).toHaveProperty('username', 'demo');
    });
  });

  // ─── GET /protected ─────────────────────────────────────────────────────────

  describe('GET /protected', () => {
    it('should return 401 without a valid session', async () => {
      const res = await request(app).get('/protected');
      expect(res.status).toBe(401);
      expect(res.body.message).toBe('Unauthorized');
    });

    it('should return 200 with a valid session', async () => {
      const agent = request.agent(app);
      await agent.post('/auth/login').send({ username: 'demo', password: 'demo123' });

      const res = await agent.get('/protected');
      expect(res.status).toBe(200);
      expect(res.body.message).toBe('This is a protected route');
    });
  });

  // ─── GET /health ─────────────────────────────────────────────────────────────

  describe('GET /health', () => {
    it('should return 200 and status ok', async () => {
      const res = await request(app).get('/health');
      expect(res.status).toBe(200);
      expect(res.body.status).toBe('ok');
    });
  });

  // ─── 404 Handler ─────────────────────────────────────────────────────────────

  describe('404 Handler', () => {
    it('should return 404 for unknown routes', async () => {
      const res = await request(app).get('/this-route-does-not-exist');
      expect(res.status).toBe(404);
    });
  });
});
